import React from 'react';
import { AnalysisResult, ModelMetrics } from '../types';

interface AnalysisResultsProps {
    results: AnalysisResult[];
    metrics: ModelMetrics;
}

const AnalysisResults: React.FC<AnalysisResultsProps> = ({ results, metrics }) => {
    return (
        <div>
            <h2>Analysis Results</h2>
            <h3>Detected Attack Types</h3>
            <ul>
                {results.map((result, index) => (
                    <li key={index}>{result.attackType}: {result.confidence}% confidence</li>
                ))}
            </ul>
            <h3>Model Metrics</h3>
            <p>Accuracy: {metrics.accuracy}</p>
            <p>Precision: {metrics.precision}</p>
            <p>Recall: {metrics.recall}</p>
            <p>F1 Score: {metrics.f1Score}</p>
        </div>
    );
};

export default AnalysisResults;
